SELECT FROM vehicle v WHERE 1 = 1
AND ( v.region_id = #{regionId} OR EXISTS ( SELECT 1 FROM region r_scope WHERE r_scope.id = v.region_id AND r_scope.province_id = #{regionId} ) )
AND v.company_id = #{companyId}
AND v.model_id = #{modelId}
AND v.model_id IN (SELECT id FROM model WHERE brand_id = #{brandId})
AND ( v.plate_number LIKE CONCAT('%', #{keyword}, '%') OR v.custom_number LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM company c WHERE c.id = v.company_id AND c.name LIKE CONCAT('%', #{keyword}, '%') ) OR EXISTS ( SELECT 1 FROM region r WHERE r.id = v.region_id AND r.name LIKE CONCAT('%', #{keyword}, '%') ) OR EXISTS ( SELECT 1 FROM model m WHERE m.id = v.model_id AND ( m.name LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM brand b WHERE b.id = m.brand_id AND b.name LIKE CONCAT('%', #{keyword}, '%') ) ) ) )
AND ( v.launch_date < #{lastLaunch}
OR (v.launch_date = #{lastLaunch} AND v.id < #{lastId})
)
AND v.launch_date IS NULL AND v.id < #{lastId}
ORDER BY CASE WHEN v.launch_date IS NULL THEN 1 ELSE 0 END ASC, v.launch_date DESC, v.id DESC LIMIT #{limit}

