AND ( v.plate_number LIKE CONCAT('%', #{keyword}, '%') OR v.custom_number LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM company c WHERE c.id = v.company_id AND c.name LIKE CONCAT('%', #{keyword}, '%') ) OR EXISTS ( SELECT 1 FROM region r WHERE r.id = v.region_id AND r.name LIKE CONCAT('%', #{keyword}, '%') ) OR EXISTS ( SELECT 1 FROM model m WHERE m.id = v.model_id AND ( m.name LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM brand b WHERE b.id = m.brand_id AND b.name LIKE CONCAT('%', #{keyword}, '%') ) ) ) )

